import axios from 'axios';

const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:8000';

const api = axios.create({
  baseURL: API_BASE_URL,
  headers: {
    'Content-Type': 'application/json',
  },
});

api.interceptors.request.use((config) => {
  const token = localStorage.getItem('token');
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
});

api.interceptors.response.use(
  (response) => response,
  (error) => {
    if (error.response?.status === 401) {
      localStorage.removeItem('token');
      window.location.href = '/login';
    }
    return Promise.reject(error);
  }
);

export const authAPI = {
  sendOtp: (phone) => api.post('/api/auth/send-otp/', { phone }),
  verifyOtp: (phone, otp) => api.post('/api/auth/verify-otp/', { phone, otp }),
  me: () => api.get('/api/auth/me/'),
};

export const productAPI = {
  list: (params) => api.get('/api/products/', { params }),
  detail: (slug) => api.get(`/api/products/${slug}/`),
  categories: () => api.get('/api/categories/'),
};

export const cartAPI = {
  reserve: (data) => api.post('/api/inventory/reserve/', data),
  sync: (items) => api.post('/api/cart/sync/', { items }),
};

export const orderAPI = {
  create: (data) => api.post('/api/orders/', data),
  list: () => api.get('/api/orders/'),
  detail: (id) => api.get(`/api/orders/${id}/`),
  track: (id) => api.get(`/api/orders/${id}/track/`),
};

export const paymentAPI = {
  createOrder: (data) => api.post('/api/payments/create-order/', data),
  verify: (data) => api.post('/api/payments/verify/', data),
};

export const adminAPI = {
  dashboard: () => api.get('/api/admin/dashboard/'),
  products: (params) => api.get('/api/admin/products/', { params }),
  updateProduct: (id, data) => api.patch(`/api/admin/products/${id}/`, data),
  orders: (params) => api.get('/api/admin/orders/', { params }),
  updateOrderStatus: (id, status) =>
    api.patch(`/api/admin/orders/${id}/`, { status }),
  tickets: () => api.get('/api/admin/tickets/'),
};

export default api;
